mapper.update:
MERGE INTO TBL_ADDR_COORD AS T USING (SELECT #{searchKey} AS SEARCH_KEY) AS S ON (T.SEARCH_KEY = S.SEARCH_KEY)
WHEN MATCHED THEN UPDATE SET UPDATE_TIME = GETDATE()
WHEN NOT MATCHED THEN INSERT ( SEARCH_KEY, RAW_ADDR, COORD_LAT, COORD_LNG, APT_NM, DONG_NM, API_TYPE, REG_TIME, UPDATE_TIME ) VALUES ( #{searchKey}, #{rawAddr}, #{lat}, #{lng}, #{aptNm}, #{dongNm}, ISNULL(#{apiType}, 'GOOGLE'), GETDATE(), GETDATE() );
